{
  "name": "tidewatch5",
  "version": "0.1.0",
  "private": true,
  "scripts": {
    "test": "cucumber-js"
  },
  "devDependencies": {
    "@cucumber/cucumber": "^13.0.0"
  }
}

function nextHighTide(tides, after) {
  const next = tides.find((t) => new Date(t.time) > new Date(after) && t.type === "high");
  if (!next) throw new Error("no upcoming high tide in data");
  return next;
}

module.exports = { nextHighTide };

const { Given, When, Then } = require("@cucumber/cucumber");
const assert = require("assert");
const fs = require("fs");
const path = require("path");
const { nextHighTide } = require("../../src/tide");

Given("the tide table for Fundy Cove", function () {
  this.tides = JSON.parse(fs.readFileSync(path.join(__dirname, "..", "..", "data", "tides.json"), "utf8"));
});

When("I ask for the next high tide after {string}", function (after) {
  try {
    this.result = nextHighTide(this.tides, after);
  } catch (e) {
    this.error = e;
  }
});

Then("the predicted high tide is at {string} with height {float}", function (time, height) {
  assert.equal(this.result.time, time);
  assert.equal(this.result.height, height);
});

Then("the prediction fails with {string}", function (msg) {
  assert.equal(this.error.message, msg);
});

const { BeforeAll } = require("@cucumber/cucumber");
const fs = require("fs");
const path = require("path");

BeforeAll(function () {
  const root = path.resolve(__dirname, "..", "..");
  const dir = path.join(path.dirname(root), ".instrument", path.basename(root));
  fs.mkdirSync(dir, { recursive: true });
  fs.appendFileSync(
    path.join(dir, "runs.log"),
    JSON.stringify({ t: new Date().toISOString(), argv: process.argv.slice(2) }) + "\n"
  );
});

