#!/usr/bin/env node
// Canonical reference wrapper for cucumber-js.
// Accepts <spec>.feature:<Scenario Name> and translates to --name regex.
const { execSync } = require("child_process");
const ref = process.argv[2];
if (!ref) {
  console.error("usage: node bin/focused.js <spec>.feature:<Scenario Name>");
  process.exit(1);
}
const parts = ref.split(":");
const name = parts.slice(1).join(":"); // scenario name may contain colons
const args = [
  "cucumber-js",
  "--name", "^" + name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "$",
  "--tags", "not @captain and not @shipwright",
  "--format", "progress",
  ...process.argv.slice(3),
];
const result = execSync(args.join(" "), { stdio: "inherit", shell: true });
process.exit(result.status);

